mapper.select:
SELECT * FROM korean_proverb
WHERE is_active = 1 AND difficulty = #{difficulty}
ORDER BY no

mapper.insert:
INSERT INTO korean_proverb (
    question, answer, option1, option2, option3, option4, 
    meaning, difficulty, is_active
) VALUES (
    #{question}, #{answer}, #{option1}, #{option2}, #{option3}, #{option4},
    #{meaning}, #{difficulty}, #{isActive}
)

mapper.update:
UPDATE korean_proverb
SET is_active = 0
WHERE no = #{no}
